CREATE OR REPLACE FUNCTION fpb_get_old_grade ( as_memno text ) RETURNS varchar AS $body$
DECLARE

ls_pregrade  sc_amnat_grade_edit.pre_grade%type;

BEGIN
--Mook 2021-03-22 Amnat
select sc_amnat_grade_edit.pre_grade into STRICT ls_pregrade
from sc_amnat_grade_edit
where 1=1
and seq_no = (
					SELECT max( tmax.seq_no ) 
					from sc_amnat_grade_edit  tmax 
					where tmax.membership_no = sc_amnat_grade_edit.membership_no
					 )
and membership_no = as_memno
;


  RETURN ls_pregrade;

  
END;
$body$
LANGUAGE PLPGSQL
SECURITY DEFINER
;
